framework_css:
/*
  Environmental research project information website
  Layout and styling based on a conservative, content-first WordPress-like theme.
*/

:root {
  /* Color system */
  --color-primary-1: #0065A8; /* deep blue */
  --color-primary-2: #0A4B78;

  --color-secondary-1: #1E8BC3; /* lighter blue */
  --color-secondary-2: #008A6E; /* teal/green */

  --color-accent: #21759B; /* classic WordPress link blue */

  --color-neutral-0: #FFFFFF;
  --color-neutral-1: #F5F5F5; /* page background */
  --color-neutral-2: #DDDDDD; /* borders, subtle controls */
  --color-neutral-3: #444444; /* primary text */
  --color-neutral-4: #777777; /* secondary text */

  --color-border-soft: #E3E3E3; /* fine separators */

  /* Semantic */
  --color-success: #2E8B57;
  --color-error: #CC3333;
  --color-warning: #E6A400;
  --color-info: #31708F;

  /* Typography */
  --font-heading: "Playfair Display", Georgia, serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Helvetica Neue", Arial, sans-serif;
  --font-code: "Source Code Pro", Menlo, Monaco, Consolas, "Courier New", monospace;

  --font-size-body: 14px;
  --font-size-small: 12px;
  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 18px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --layout-max-width: 1160px;
}

/* Global reset / base ----------------------------------------------------- */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body.site {
  margin: 0;
  padding: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-relaxed);
  color: var(--color-neutral-3);
  background-color: var(--color-neutral-1);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-accent);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.site-container {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* Typography -------------------------------------------------------------- */

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  font-weight: 600;
  color: #222222;
  margin: 0 0 var(--space-3);
  line-height: var(--line-height-tight);
}

h1 {
  font-size: var(--font-size-h1);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0 0 var(--space-3);
}

small,
.footer-copy {
  font-size: var(--font-size-small);
}

code,
pre {
  font-family: var(--font-code);
}

/* Header ------------------------------------------------------------------ */

.site-header {
  background-color: var(--color-neutral-0);
  border-bottom: 1px solid var(--color-border-soft);
}

.header-top-bar {
  border-bottom: 1px solid var(--color-border-soft);
}

.header-top-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-1) var(--space-3);
  display: flex;
  align-items: center;
  justify-content: space-between;
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
}

.header-main {
  background-color: var(--color-neutral-0);
}

.header-main-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3) var(--space-3);
}

.site-branding {
  display: flex;
  align-items: flex-end;
}

.site-logo-link {
  display: inline-flex;
  flex-direction: column;
  text-decoration: none;
}

.site-logo-text-primary {
  font-family: var(--font-heading);
  font-size: 26px;
  letter-spacing: 0.02em;
  color: var(--color-primary-1);
}

.site-logo-text-secondary {
  font-family: var(--font-heading);
  font-size: 18px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--color-secondary-2);
}

/* Primary navigation ------------------------------------------------------ */

.primary-navigation {
  border-top: 1px solid #EFEFEF;
  border-bottom: 1px solid var(--color-border-soft);
  background-color: var(--color-neutral-0);
}

.primary-navigation-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
}

.primary-menu {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
}

.primary-menu > .menu-item {
  margin: 0;
}

.primary-menu > .menu-item > a {
  display: block;
  padding: 12px 18px;
  font-size: var(--font-size-body);
  letter-spacing: 0.04em;
  color: var(--color-neutral-3);
  text-decoration: none;
}

.primary-menu > .menu-item > a:hover,
.primary-menu > .menu-item > a:focus {
  color: var(--color-accent);
  border-bottom: 2px solid var(--color-accent);
  margin-bottom: -2px; /* retain overall header height */
}

.primary-menu > .menu-item.current-menu-item > a {
  color: var(--color-accent);
  font-weight: 600;
}

/* Main layout ------------------------------------------------------------- */

.site-main-wrapper {
  flex: 1;
}

.site-main-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-5) var(--space-3) var(--space-6);
  display: flex;
  align-items: flex-start;
}

.site-content {
  flex: 0 0 68%;
  min-width: 0;
  background-color: var(--color-neutral-0);
  border: 1px solid var(--color-border-soft);
  padding: var(--space-4);
}

.site-sidebar {
  flex: 0 0 27%;
  margin-left: var(--space-5);
  background-color: var(--color-neutral-0);
  border: 1px solid var(--color-border-soft);
  padding: var(--space-3);
  min-height: 200px; /* visual balance even when empty */
}

/* Footer ------------------------------------------------------------------ */

.site-footer {
  background-color: var(--color-neutral-0);
  border-top: 1px solid var(--color-border-soft);
}

.footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-4) var(--space-3) var(--space-4);
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
}

.footer-links {
  margin-bottom: var(--space-2);
}

.footer-links a {
  color: var(--color-neutral-4);
}

.footer-links a:hover,
.footer-links a:focus {
  color: var(--color-accent);
  text-decoration: underline;
}

.footer-separator {
  margin: 0 var(--space-1);
  color: var(--color-neutral-2);
}

.footer-meta {
  color: var(--color-neutral-4);
}

.footer-copy {
  margin: 0;
}

/* Responsive adjustments -------------------------------------------------- */

@media (max-width: 960px) {
  .header-main-inner {
    padding: var(--space-3) var(--space-3) var(--space-2);
  }

  .primary-menu {
    flex-wrap: wrap;
  }

  .primary-menu > .menu-item > a {
    padding: 10px 12px;
  }

  .site-main-inner {
    flex-direction: column;
  }

  .site-content {
    flex: 1 1 auto;
  }

  .site-sidebar {
    flex: 1 1 auto;
    margin-left: 0;
    margin-top: var(--space-4);
  }

  .footer-inner {
    align-items: center;
    text-align: center;
  }
}

@media (max-width: 600px) {
  .header-top-inner,
  .primary-navigation-inner,
  .site-main-inner,
  .footer-inner {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }

  .site-logo-text-primary {
    font-size: 22px;
  }

  .site-logo-text-secondary {
    font-size: 14px;
  }
}
